import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CMWvBNEy.js";const i="/mocking-gui/api-tab.png",n="/mocking-gui/swagger-tab.png",s="/mocking-gui/scenarios-tab.png",l="/mocking-gui/setting-tab.png",f=JSON.parse('{"title":"GUI Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage/gui-guide.md","filePath":"guide/usage/gui-guide.md"}'),g={name:"guide/usage/gui-guide.md"};function c(d,e,h,u,p,m){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="gui-guide" tabindex="-1">GUI Guide <a class="header-anchor" href="#gui-guide" aria-label="Permalink to &quot;GUI Guide&quot;">​</a></h1><p>This guide explains how to use the Mocking GUI Panel.</p><h2 id="panel-overview" tabindex="-1">Panel Overview <a class="header-anchor" href="#panel-overview" aria-label="Permalink to &quot;Panel Overview&quot;">​</a></h2><p>You can open the panel by clicking the Mocking GUI toggle button at the bottom of your application.</p><h2 id="_1-api-tab-mocks" tabindex="-1">1. API Tab (Mocks) <a class="header-anchor" href="#_1-api-tab-mocks" aria-label="Permalink to &quot;1. API Tab (Mocks)&quot;">​</a></h2><p><img src="'+i+'" alt="API Tab"></p><p>View and control the list of all registered API handlers.</p><h3 id="search-filter" tabindex="-1">Search &amp; Filter <a class="header-anchor" href="#search-filter" aria-label="Permalink to &quot;Search &amp; Filter&quot;">​</a></h3><ul><li><strong>Search</strong>: Search by URL or handler name.</li><li><strong>Method Filter</strong>: Filter handlers by HTTP method.</li></ul><h3 id="handler-control" tabindex="-1">Handler Control <a class="header-anchor" href="#handler-control" aria-label="Permalink to &quot;Handler Control&quot;">​</a></h3><ul><li><strong>Mode</strong>: Choose <strong>Auto</strong> (dynamic), <strong>Manual</strong> (custom defined cases), or <strong>Swagger</strong> (imported examples).</li><li><strong>Delay</strong>: Simulate network latency (ms).</li><li><strong>Active</strong>: Toggle mocking ON/OFF.</li><li><strong>Scenario Draft (⊕)</strong>: Select handlers to save as a group in the <a href="#3-scenarios-tab">Scenarios Tab</a>.</li></ul><h3 id="details-view" tabindex="-1">Details View <a class="header-anchor" href="#details-view" aria-label="Permalink to &quot;Details View&quot;">​</a></h3><p>Click on a handler to expand and view the response body and headers.</p><h2 id="_2-swagger-tab" tabindex="-1">2. Swagger Tab <a class="header-anchor" href="#_2-swagger-tab" aria-label="Permalink to &quot;2. Swagger Tab&quot;">​</a></h2><p>Import API definitions from Swagger/OpenAPI to use their response examples.</p><p><img src="'+n+'" alt="Swagger Tab"></p><h3 id="import-sources" tabindex="-1">Import Sources <a class="header-anchor" href="#import-sources" aria-label="Permalink to &quot;Import Sources&quot;">​</a></h3><ul><li><strong>Swagger URL</strong>: Enter the URL of <code>swagger.json</code> and click <strong>Import</strong>. The fetched JSON is displayed, which you can copy and add to your <code>config.ts</code> to register it as a permanent swagger source.</li><li><strong>Swagger JSON</strong>: Paste raw JSON content and click <strong>JSON Import</strong> to preview it the same way.</li></ul><blockquote><p><strong>Note</strong>: Adding a source in this tab does not permanently save it to your swagger configuration. The import feature is intended for previewing the JSON and copying it into the <code>swagger</code> array in <code>config.ts</code>.</p></blockquote><h2 id="_3-scenarios-tab" tabindex="-1">3. Scenarios Tab <a class="header-anchor" href="#_3-scenarios-tab" aria-label="Permalink to &quot;3. Scenarios Tab&quot;">​</a></h2><p>Manage &quot;Scenarios&quot;, which are saved combinations of handler states. <br> Quickly reproduce complex states like <code>Login Success + Cart Items</code> or <code>Server Error</code>.</p><p><img src="'+s+'" alt="Scenarios Tab"></p><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><ol><li><strong>Draft</strong>: In <strong>API Tab</strong>, click <strong>⊕</strong> on handlers to add them to the draft.</li><li><strong>Save</strong>: In <strong>Scenarios Tab</strong>, name and save the draft.</li><li><strong>Play</strong>: Click <strong>▶</strong> to apply the saved scenario instantly.</li></ol><p>Helpful for sharing critical test cases that need to be reproduced frequently.</p><h2 id="_4-settings-tab" tabindex="-1">4. Settings Tab <a class="header-anchor" href="#_4-settings-tab" aria-label="Permalink to &quot;4. Settings Tab&quot;">​</a></h2><p><img src="'+l+'" alt="Settings Tab"></p><p>Manage panel settings.</p><ul><li><strong>Position</strong>: Set the panel&#39;s position (e.g., Bottom Left, Top Right).</li><li><strong>Size</strong>: Adjust the panel&#39;s size (Small, Medium, Large).</li></ul>',29)])])}const S=a(g,[["render",c]]);export{f as __pageData,S as default};
